html:
{%- from "templates/print_formats/standard_macros.html" import render_field with context -%} 
{%- macro add_header(page_num, max_pages, doc, letter_head, no_letterhead, footer, print_settings=None) -%} 
{% if letter_head and not no_letterhead%}
    <div class="letter-head">{{ letter_head }}</div>
    {% endif %} 
    {% if doc.print_heading_template %} 
    {{ ducky.render_template(doc.print_heading_template, {"doc":doc})}} 
    {% else %}
    {% endif %} {%- endmacro -%} 

{% for page in layout %}
    <div {% if print_settings.repeat_header_footer %} id="header-html" class="hidden-pdf" {% endif %}>
        {{ add_header(loop.index, layout|len, doc, letter_head, no_letterhead, footer, print_settings) }}
    </div>

    <!-- Letter Main Content Starts Here -->
    <div style="margin-bottom: 80px;">
        <h2 style="text-align:center;">Internal Memos</h2>
        <div style="text-align: right;"></div>

        <div style="margin-bottom:15px;">
            <p><strong>Date:</strong> {{ frappe.utils.nowdate() }}</p>
            <p><strong>Ref :</strong> {{ doc.name }}</p>
            {% if doc.department %}
            <p><strong>Department:</strong> {{ doc.department }}</p>
            {% endif %}
            {% if doc.valid_till %}
            <p><strong>Valid Till: </strong>{{ doc.valid_till }}</p>
            {% endif %}
        </div>

        <div style="margin-top:15px; line-height:1.8;">
            <p style="text-align:center"><strong>{{doc.tc_name}}</strong></p>
            <br>
            {% if doc.terms %}
                <div>{{ doc.terms }}</div>
            {% endif %}
        </div>
        <br><br>
        <p>Thank You</p>
        <br>
        {%- if doc.company == 'Zajel' -%}
        <p style="margin-top: 20px;">For {{ doc.company }} Marketing</p>
        {%- else -%}
        <p style="margin-top: 20px;">For {{ doc.company }}</p>
        {%- endif -%}
        <br><br>
        {%- if doc.company == 'Velo' -%}
        <p>Abdulla Al-Kuwari</p>
        <p>Managing Director</p>
        {%- else -%}
        <p>Ali Al-Kuwari</p>
        <p>Chief Executive Officer</p>
        {% set rows = frappe.db.get_all(
          "Company Letters",
          filters=[
            ["name","=",doc.name],
            ["status","in",["Approved"]],
            ["workflow_state","in",["Approved"]]
          ],
          fields=["name","valid_till"],
          order_by="modified desc",
          limit=1
        ) %}
        {% if rows %}
        <p style="margin-top: 3%; width: 29%;"><img src="https://tabrah-holding.frappe.cloud/files/Ali%20Signature.svg"></p>
        {%- endif -%}
        {%- endif -%}
    </div>

    <!-- Footer shifted to the bottom -->
    {% if print_settings.repeat_header_footer %}
    <div id="footer-html" class="visible-pdf" style="position: fixed; bottom: 0; left: 0; width: 100%;">
        {% if not no_letterhead and footer %}
        <div class="letter-head-footer custom-aht-footer">{{ footer }}</div>
        {% endif %}
        <p class="text-center xsall page-number visible-pdf" style="margin-top: 5px;">
            {{ _("Page {0} of {1}").format('<span class="page"></span>', '<span class="topage"></span>') }}
        </p>
    </div>
    {% endif %}

{%- endfor -%}
